'use client';

import { useState, useEffect } from 'react';
import Link from 'next/link';
import {
    FileUp,
    History,
    Search,
    CheckCircle2,
    Download,
    BrainCircuit,
    Clock,
    ArrowRight
} from 'lucide-react';
import { supabase } from '@/lib/supabase';

export default function PublicDashboard({ user }: { user: any }) {
    const [file, setFile] = useState<File | null>(null);
    const [documents, setDocuments] = useState<any[]>([]);
    const [uploading, setUploading] = useState(false);
    const [step, setStep] = useState(0); // 0:Idle, 1:Uploading, 2:Scanning, 3:AI Analyzing, 4:Done

    useEffect(() => {
        fetchDocuments();
    }, []);

    const fetchDocuments = async () => {
        const { data, error } = await supabase
            .from('legal_documents')
            .select('*')
            .order('created_at', { ascending: false });

        if (data) setDocuments(data);
    };

    const handleUpload = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!file) return;

        setUploading(true);
        setStep(1);

        try {
            // 1. Extract text (Simplified for now, just filename + placeholder)
            const text_content = `Content for ${file.name}: Legal case analysis required for ${file.name}.`;

            // 2. Insert into Supabase
            const { data, error } = await supabase
                .from('cases')
                .insert([{
                    filename: file.name,
                    owner_id: user.id,
                    content_text: text_content,
                    status: 'processing'
                }])
                .select();

            if (error) throw error;

            // 3. Call AI Logic (Edge Function)
            setStep(2);
            await new Promise(r => setTimeout(r, 1000));
            setStep(3);

            const { error: fnError } = await supabase.functions.invoke('classify-case', {
                body: { record: data[0] }
            });

            if (fnError) console.error("AI Skill Error:", fnError);

            setStep(4);
            await fetchDocuments();
            setFile(null);
            setTimeout(() => {
                setUploading(false);
                setStep(0);
            }, 1500);
        } catch (err: any) {
            alert(`Error: ${err.message}`);
            setUploading(false);
        }
    };

    return (
        <div className="max-w-7xl mx-auto px-4 py-12 space-y-10">
            <header className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div>
                    <h1 className="text-3xl font-black text-slate-900 tracking-tight">Personal Dashboard</h1>
                    <p className="text-slate-500 font-medium">Manage and track your AI-processed legal documents</p>
                </div>
                <div className="bg-indigo-600 px-4 py-2 rounded-xl text-white text-sm font-bold shadow-lg shadow-indigo-600/20">
                    Status: Verified Citizen
                </div>
            </header>

            {/* Upload Section */}
            <section className="bg-white rounded-3xl shadow-xl shadow-slate-200/50 border border-slate-100 overflow-hidden">
                <div className="p-8 border-b border-slate-50">
                    <h2 className="text-xl font-bold text-slate-900 flex items-center gap-2">
                        <FileUp className="h-5 w-5 text-indigo-600" /> New Case Submission
                    </h2>
                </div>

                <div className="p-8">
                    {uploading ? (
                        <div className="py-8">
                            <div className="flex justify-between items-center max-w-2xl mx-auto mb-10 relative">
                                <div className="absolute top-5 left-0 w-full h-1 bg-slate-100 -z-10"></div>
                                {[
                                    { id: 1, label: 'Uploading', icon: <FileUp className="h-4 w-4" /> },
                                    { id: 2, label: 'Scanning', icon: <Search className="h-4 w-4" /> },
                                    { id: 3, label: 'AI Resolution', icon: <BrainCircuit className="h-4 w-4" /> },
                                    { id: 4, label: 'Solved', icon: <CheckCircle2 className="h-4 w-4" /> }
                                ].map((s) => (
                                    <div key={s.id} className="flex flex-col items-center gap-3">
                                        <div className={`h-10 w-10 rounded-full flex items-center justify-center border-4 transition-all duration-500 bg-white ${step >= s.id ? 'border-indigo-600 text-indigo-600' : 'border-slate-100 text-slate-300'}`}>
                                            {step > s.id ? <CheckCircle2 className="h-5 w-5" /> : s.icon}
                                        </div>
                                        <span className={`text-[10px] font-black uppercase tracking-widest ${step >= s.id ? 'text-indigo-600' : 'text-slate-400'}`}>{s.label}</span>
                                    </div>
                                ))}
                            </div>
                            <p className="text-center text-slate-500 font-medium animate-pulse italic">Applying neural classification models to document content...</p>
                        </div>
                    ) : (
                        <form onSubmit={handleUpload} className="flex flex-col md:flex-row gap-6 items-end">
                            <div className="flex-1 w-full">
                                <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-3 ml-1">Select Legal Document (PDF, TXT)</label>
                                <div className="relative group/file">
                                    <input
                                        type="file"
                                        onChange={e => setFile(e.target.files?.[0] || null)}
                                        className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10"
                                        accept=".pdf,.txt"
                                    />
                                    <div className="w-full p-4 bg-slate-50 border-2 border-dashed border-slate-200 rounded-2xl group-hover/file:border-indigo-400 group-hover/file:bg-indigo-50 transition-all flex items-center justify-between">
                                        <span className="text-slate-500 font-medium truncate">
                                            {file ? file.name : 'Click or drag file here to upload'}
                                        </span>
                                        <div className="bg-white px-3 py-1.5 rounded-lg border border-slate-200 text-xs font-bold text-slate-700 shadow-sm">
                                            Browse Files
                                        </div>
                                    </div>
                                </div>
                            </div>
                            <button
                                type="submit"
                                disabled={!file}
                                className="w-full md:w-auto px-8 py-4 bg-indigo-600 hover:bg-slate-900 text-white rounded-2xl font-bold transition-all shadow-lg shadow-indigo-600/10 disabled:opacity-50 flex items-center justify-center gap-2"
                            >
                                Analyze Case <ArrowRight className="h-5 w-5" />
                            </button>
                        </form>
                    )}
                </div>
            </section>

            {/* History Section */}
            <section className="space-y-6">
                <h2 className="text-xl font-bold text-slate-900 flex items-center gap-2">
                    <History className="h-5 w-5 text-indigo-600" /> Case Revision History
                </h2>

                <div className="grid gap-6">
                    {documents.map(doc => (
                        <div key={doc.id} className="bg-white rounded-3xl p-8 border border-slate-100 shadow-sm hover:shadow-xl hover:shadow-indigo-500/5 transition group">
                            <div className="flex flex-col lg:flex-row justify-between gap-6">
                                <div className="space-y-4 flex-grow">
                                    <div className="flex items-center gap-3">
                                        <h3 className="text-xl font-black text-slate-900 tracking-tight">{doc.filename}</h3>
                                        <span className="px-3 py-1 bg-emerald-100 text-emerald-700 text-[10px] font-black uppercase tracking-widest rounded-full">AI Solved</span>
                                    </div>

                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                        <div className="p-4 bg-slate-50 rounded-2xl border border-slate-100">
                                            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Categorization</p>
                                            <div className="flex items-center gap-3">
                                                <span className="text-indigo-600 font-bold">{doc.category}</span>
                                                <div className="h-1 flex-grow bg-slate-200 rounded-full overflow-hidden">
                                                    <div
                                                        className="h-full bg-indigo-500 transition-all duration-1000"
                                                        style={{ width: `${(doc.confidence * 100) || 0}%` }}
                                                    ></div>
                                                </div>
                                                <span className="text-xs font-bold text-slate-500">{Math.round(doc.confidence * 100)}%</span>
                                            </div>
                                        </div>

                                        <div className="p-4 bg-indigo-50 rounded-2xl border border-indigo-100">
                                            <p className="text-[10px] font-black text-indigo-400 uppercase tracking-widest mb-2">AI Resolution Recommendation</p>
                                            <p className="text-sm text-indigo-900 font-bold leading-relaxed">{doc.resolution}</p>
                                        </div>
                                    </div>
                                </div>

                                <div className="lg:w-48 flex flex-col justify-between border-t lg:border-t-0 lg:border-l border-slate-100 pt-6 lg:pt-0 lg:pl-6">
                                    <div className="space-y-1">
                                        <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Processed On</p>
                                        <div className="flex items-center gap-2 text-slate-900 font-bold text-sm">
                                            <Clock className="h-3 w-3 text-indigo-600" /> {new Date().toLocaleDateString()}
                                        </div>
                                    </div>

                                    <button
                                        onClick={() => alert("Check Supabase Storage 'documents' bucket for official FIR exports.")}
                                        className="mt-6 flex items-center justify-center gap-2 w-full py-3 bg-slate-900 hover:bg-indigo-600 text-white text-xs font-bold rounded-xl transition duration-300"
                                    >
                                        <Download className="h-4 w-4" /> Download FIR
                                    </button>
                                </div>
                            </div>
                        </div>
                    ))}

                    {documents.length === 0 && (
                        <div className="text-center py-20 bg-white rounded-3xl border border-dashed border-slate-200">
                            <div className="bg-slate-50 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4">
                                <Search className="h-8 w-8 text-slate-300" />
                            </div>
                            <p className="text-slate-500 font-bold">No registered documents found.</p>
                            <p className="text-slate-400 text-sm">Upload your first case to see the AI in action.</p>
                        </div>
                    )}
                </div>
            </section>
        </div>
    );
}
